def load_jsonl_files(directory: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not directory.exists():
        return rows
    for path in sorted(directory.rglob("*.jsonl"), key=lambda item: item.stat().st_mtime):
        for line in path.read_text(encoding="utf-8").splitlines():
            if not line.strip():
                continue
            item = json.loads(line)
            item["_source"] = str(path)
            rows.append(item)
    return rows

def load_json_files(directory: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not directory.exists():
        return rows
    for path in sorted(directory.glob("*.json"), key=lambda item: item.stat().st_mtime):
        try:
            item = json.loads(path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            continue
        item["_source"] = str(path)
        rows.append(item)
    return rows

def load_json_files_recursive(directory: Path, pattern: str = "*.json") -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not directory.exists():
        return rows
    for path in sorted(directory.rglob(pattern), key=lambda item: item.stat().st_mtime):
        try:
            item = json.loads(path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            continue
        item["_source"] = str(path)
        rows.append(item)
    return rows

def load_runs(directory: Path) -> list[dict[str, Any]]:
    if not directory.exists():
        return []
    runs: list[dict[str, Any]] = []
    for path in sorted(directory.glob("*.json"), key=lambda item: item.stat().st_mtime):
        try:
            item = json.loads(path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            continue
        item["_source"] = str(path)
        item["tool_sequence"] = collect_tool_sequence(item)
        item["usage"] = collect_usage(item)
        runs.append(item)
    return runs

def load_json(path: Path, default: dict[str, Any]) -> dict[str, Any]:
    if not path.exists():
        return default
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError:
        return default

def collect_tool_sequence(run: dict[str, Any]) -> list[str]:
    sequence: list[str] = []
    for message in run.get("messages", []):
        if message.get("role") != "assistant":
            continue
        for call in message.get("tool_calls") or []:
            sequence.append(str(call.get("name", "")))
    return sequence

def collect_usage(run: dict[str, Any]) -> dict[str, int | float]:
    usage: dict[str, int | float] = {}
    for message in run.get("messages", []):
        if message.get("role") != "assistant":
            continue
        item = message.get("usage") or {}
        if not isinstance(item, dict):
            continue
        for key, value in item.items():
            if isinstance(value, (int, float)):
                usage[key] = usage.get(key, 0) + value
    return usage

