def dataset_metadata(path: Path, task_count: int) -> dict[str, Any]:
    content = path.read_bytes()
    return {
        "path": str(path),
        "sha256": hashlib.sha256(content).hexdigest(),
        "task_count": task_count,
        "bytes": len(content),
